import java.util.Deque;
import java.util.LinkedList;

public class Solution {
    public static long solve(long[] weight) {
        Deque<Integer> dq = new LinkedList<>();
        int start = 0;
        long count = 0;
        for (int i = 0; i < weight.length; i++) {
            while (!dq.isEmpty() && dq.peekFirst() < start) {
                dq.pollFirst();
            }
            while (!dq.isEmpty() && weight[i] >= weight[dq.peekLast()]) {
                dq.pollLast();
            }
            dq.offerLast(i);
            int currentMaxIndex = dq.peekFirst();
            long currentMax = weight[currentMaxIndex];
            if (currentMax > weight[i]) {
                count++;
                start = i + 1;
                dq.clear();
            }
        }
        return count;
    }
}
